code = """import pandas as pd\nimport json\nimport re\n\ntool_output = locals()['var_function-call-16761073810345406468']\nresults_list_of_strings = tool_output['query_db_response']['results']\nfull_output_string = results_list_of_strings[0]\n\n# Extract the JSON array string using regex, from the first '[' to the last ']'\nmatch = re.search(r'\\[.*\\]', full_output_string, re.DOTALL)\n\narticles_data = []\nif match:\n    json_string = match.group(0)\n\n    # Replace non-standard escape for single quote: '\\\\\\' (which Python interprets as \\') with just '\''\n    # The raw string contains `\\\\'` which is a literal `\` followed by a literal `'`. \n    # `json.loads` expects a literal `'` in a double-quoted string, or `\\'` if the string itself used single quotes.\n    # So we replace `\\\\'` with `'`.\n    json_string_corrected_single_quotes = json_string.replace(\"\\\\\'\", \"\'\")\n    \n    # Replace escaped backslashes: `\\\\\\\\` (which Python interprets as `\\\\`) with `\\\\`.\n    # The raw string contains `\\\\\\\\` which is a literal `\\\\`. `json.loads` expects `\\\\` for a literal backslash.\n    # This replacement is to fix the `\\\\` which comes from the database side and is escaped for JSON, but the Python string literal then double-escapes it.\n    # So, `\\\\\\\\` (four backslashes) in the Python string should become `\\\\` (two backslashes) for `json.loads`.\n    json_string_final = json_string_corrected_single_quotes.replace(\"\\\\\\\\\", \"\\\\\")\n\n    try:\n        articles_data = json.loads(json_string_final)\n    except json.JSONDecodeError as e:\n        # Fallback if the above replacements didn't fix it, try simpler replacement or log error\n        result = f\"JSON decoding failed after correction: {e}\"\n        print('__RESULT__:')\n        print(json.dumps(result))\n        exit()\n\ndf = pd.DataFrame(articles_data)\n\ndef is_sports(title, description):\n    sports_keywords = ['sport', 'team', 'game', 'match', 'athlete', 'player', 'coach', 'league', 'championship', 'olympic', 'football', 'basketball', 'baseball', 'soccer', 'tennis', 'golf', 'race', 'cup', 'medal']\n    title_lower = title.lower()\n    description_lower = description.lower()\n    for keyword in sports_keywords:\n        if keyword in title_lower or keyword in description_lower:\n            return True\n    return False\n\nsports_articles = df[df.apply(lambda row: is_sports(row['title'], row['description']), axis=1)]\n\nif not sports_articles.empty:\n    sports_articles = sports_articles.copy() # Avoid SettingWithCopyWarning\n    sports_articles['description_length'] = sports_articles['description'].apply(len)\n    longest_description_article = sports_articles.loc[sports_articles['description_length'].idxmax()]\n    result = longest_description_article['title']\nelse:\n    result = \"No sports articles found.\"\n\nprint('__RESULT__:')\nprint(json.dumps(result))"""

